        def __init__(self, label, plain_m2m=None):
            self.label = label
            self.plain_m2m = plain_m2m or []


    class Other(object):
        def __init__(self, label):
            self.label = label


    class BaseFactory(factory.Factory):
        label = FuzzyText()


    class OtherFactory(BaseFactory):
